#!/usr/bin/env perl
use strict;
use warnings;
use File::Spec;
use File::Basename;
use Cwd 'abs_path';

my $config_dir = $ARGV[0] || 'plugins';
my $plugin_context = {};

sub load_plugin_config {
    my ($config_file) = @_;
    my %config;
    
    open my $fh, '<', $config_file or die "Cannot open config file $config_file: $!";
    
    my $current_section = '';
    my $code_block = '';
    my $in_code_block = 0;
    
    while (my $line = <$fh>) {
        chomp $line;
        
        next if $line =~ /^\s*#/;
        next if $line =~ /^\s*$/;
        
        if ($line =~ /^\[(\w+)\]$/) {
            if ($in_code_block && $current_section) {
                $config{$current_section} = $code_block;
                $code_block = '';
                $in_code_block = 0;
            }
            $current_section = $1;
            next;
        }
        
        if ($line =~ /^(\w+)\s*=\s*(.+)$/) {
            $config{$1} = $2;
        } elsif ($current_section eq 'code') {
            $in_code_block = 1;
            $code_block .= $line . "\n";
        }
    }
    
    if ($in_code_block && $current_section) {
        $config{$current_section} = $code_block;
    }
    
    close $fh;
    return \%config;
}

sub execute_plugin {
    my ($plugin_name, $plugin_code, $context) = @_;
    
    print "Executing plugin: $plugin_name\n";
    print "=" x 60 . "\n";
    
    my $result;
    my $error;
    
    {
        local $@;
        $result = eval $plugin_code;
        $error = $@;
    }
    
    if ($error) {
        print "ERROR in plugin '$plugin_name': $error\n";
        return undef;
    }
    
    print "Plugin '$plugin_name' executed successfully\n";
    print "Result: " . (defined $result ? $result : 'undef') . "\n";
    print "=" x 60 . "\n\n";
    
    return $result;
}

sub load_all_plugins {
    my ($dir) = @_;
    my @plugins;
    
    unless (-d $dir) {
        print "Plugin directory '$dir' does not exist. Creating it...\n";
        mkdir $dir or die "Cannot create directory $dir: $!";
        create_sample_plugins($dir);
    }
    
    opendir my $dh, $dir or die "Cannot open directory $dir: $!";
    my @files = grep { /\.conf$/ && -f "$dir/$_" } readdir($dh);
    closedir $dh;
    
    foreach my $file (sort @files) {
        my $full_path = File::Spec->catfile($dir, $file);
        my $config = load_plugin_config($full_path);
        
        if ($config->{code}) {
            push @plugins, {
                name => $config->{name} || $file,
                enabled => $config->{enabled} // 1,
                priority => $config->{priority} || 50,
                code => $config->{code},
                file => $file
            };
        }
    }
    
    @plugins = sort { $a->{priority} <=> $b->{priority} } @plugins;
    
    return \@plugins;
}

