sub main {
    print "Extensible Perl Plugin System\n";
    print "=" x 60 . "\n\n";
    
    my $plugins = load_all_plugins($config_dir);
    
    print "Loaded " . scalar(@$plugins) . " plugin(s)\n\n";
    
    foreach my $plugin (@$plugins) {
        next unless $plugin->{enabled};
        
        my $result = execute_plugin(
            $plugin->{name},
            $plugin->{code},
            $plugin_context
        );
        
        $plugin_context->{$plugin->{name}} = $result;
    }
    
    print "All plugins executed.\n";
    print "Plugin results stored in context:\n";
    foreach my $key (keys %$plugin_context) {
        print "  $key => " . (defined $plugin_context->{$key} ? $plugin_context->{$key} : 'undef') . "\n";
    }
}

main();